import React, { useState } from 'react'
import { BrowserRouter, Routes, Route, useNavigate, useLocation } from 'react-router-dom'
import Home from './pages/Home'
import Week from './pages/Week'
import Tasks from './pages/Tasks'
import Projects from './pages/Projects'
import Notes from './pages/Notes'
import Habits from './pages/Habits'
import TaskModal from './components/TaskModal'

const NAV = [
  { path: '/',         label: 'Home',     icon: HomeIcon },
  { path: '/week',     label: 'Week',     icon: WeekIcon },
  { path: '/tasks',    label: 'Tasks',    icon: TasksIcon },
  { path: '/projects', label: 'Projects', icon: ProjectsIcon },
  { path: '/notes',    label: 'Notes',    icon: NotesIcon },
  { path: '/habits',   label: 'Habits',   icon: HabitsIcon },
]

function Shell() {
  const navigate = useNavigate()
  const location = useLocation()
  const [taskModal, setTaskModal] = useState(null) // null | 'today' | 'scheduled'

  return (
    <div className="app-shell">
      <div className="page-scroll">
        <Routes>
          <Route path="/"         element={<Home onAddTask={setTaskModal} />} />
          <Route path="/week"     element={<Week onAddTask={setTaskModal} />} />
          <Route path="/tasks"    element={<Tasks onAddTask={setTaskModal} />} />
          <Route path="/projects" element={<Projects />} />
          <Route path="/notes"    element={<Notes />} />
          <Route path="/habits"   element={<Habits />} />
        </Routes>
      </div>

      <nav className="bottom-nav">
        {NAV.map(({ path, label, icon: Icon }) => (
          <div
            key={path}
            className={`nav-item${location.pathname === path ? ' active' : ''}`}
            onClick={() => navigate(path)}
          >
            <Icon active={location.pathname === path} />
            <span>{label}</span>
          </div>
        ))}
      </nav>

      {taskModal && (
        <TaskModal
          mode={taskModal}
          onClose={() => setTaskModal(null)}
        />
      )}
    </div>
  )
}

export default function App() {
  return (
    <BrowserRouter>
      <Shell />
    </BrowserRouter>
  )
}

// ── Nav Icons ──────────────────────────────────────────────────────────────────
function HomeIcon({ active }) {
  const c = active ? '#d4520f' : '#666'
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <rect x="2" y="2" width="7" height="7" rx="2" fill={c} />
      <rect x="11" y="2" width="7" height="7" rx="2" fill={c} opacity="0.5" />
      <rect x="2" y="11" width="7" height="7" rx="2" fill={c} opacity="0.5" />
      <rect x="11" y="11" width="7" height="7" rx="2" fill={c} opacity="0.5" />
    </svg>
  )
}
function WeekIcon({ active }) {
  const c = active ? '#d4520f' : '#666'
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <rect x="2" y="4" width="16" height="13" rx="2" stroke={c} strokeWidth="1.5" />
      <line x1="2" y1="8" x2="18" y2="8" stroke={c} strokeWidth="1.5" />
      <line x1="7" y1="2" x2="7" y2="6" stroke={c} strokeWidth="1.5" strokeLinecap="round" />
      <line x1="13" y1="2" x2="13" y2="6" stroke={c} strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  )
}
function TasksIcon({ active }) {
  const c = active ? '#d4520f' : '#666'
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <circle cx="5" cy="6" r="1.5" fill={c} />
      <line x1="8" y1="6" x2="18" y2="6" stroke={c} strokeWidth="1.5" strokeLinecap="round" />
      <circle cx="5" cy="10" r="1.5" fill={c} opacity="0.6" />
      <line x1="8" y1="10" x2="15" y2="10" stroke={c} strokeWidth="1.5" strokeLinecap="round" opacity="0.6" />
      <circle cx="5" cy="14" r="1.5" fill={c} opacity="0.4" />
      <line x1="8" y1="14" x2="13" y2="14" stroke={c} strokeWidth="1.5" strokeLinecap="round" opacity="0.4" />
    </svg>
  )
}
function ProjectsIcon({ active }) {
  const c = active ? '#d4520f' : '#666'
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <rect x="2" y="3" width="16" height="3" rx="1.5" fill={c} />
      <rect x="2" y="9" width="11" height="3" rx="1.5" fill={c} opacity="0.6" />
      <rect x="2" y="15" width="7" height="3" rx="1.5" fill={c} opacity="0.4" />
    </svg>
  )
}
function NotesIcon({ active }) {
  const c = active ? '#d4520f' : '#666'
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <rect x="3" y="2" width="14" height="16" rx="2" stroke={c} strokeWidth="1.5" />
      <line x1="7" y1="7" x2="13" y2="7" stroke={c} strokeWidth="1.5" strokeLinecap="round" />
      <line x1="7" y1="10" x2="13" y2="10" stroke={c} strokeWidth="1.5" strokeLinecap="round" />
      <line x1="7" y1="13" x2="10" y2="13" stroke={c} strokeWidth="1.5" strokeLinecap="round" />
    </svg>
  )
}
function HabitsIcon({ active }) {
  const c = active ? '#d4520f' : '#666'
  return (
    <svg width="20" height="20" viewBox="0 0 20 20" fill="none">
      <circle cx="10" cy="10" r="7.5" stroke={c} strokeWidth="1.5" />
      <polyline points="7,10 9,12 13,8" stroke={c} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  )
}
